<template>
    <apexchart type="bar" height="350" :options="chartOptions" :series="series" />
</template>

<script>
import VueApexCharts from 'vue-apexcharts';
export default {
    components: {
        apexchart: VueApexCharts,
    },
    props: ['series', 'yMax', 'chartColors', 'dateRange'],
    data: () => ({
        chartOptions: {
            chart: {
                type: 'bar',
                height: 350,
                events: {
                    click: (chart, w, e) => {
                        console.log(chart, w, e);
                    },
                },
                toolbar: {
                    show: false,
                },
            },
            plotOptions: {
                bar: {
                    horizontal: false,
                    columnWidth: '55%',
                    endingShape: 'rounded',
                },
            },
            dataLabels: {
                enabled: false,
            },
            stroke: {
                show: true,
                width: 2,
                colors: ['transparent'],
            },
            xaxis: {},
            yaxis: {
                // title: {
                //     text: '$ (thousands)',
                // },
                min: 0,
            },
            fill: {
                opacity: 1,
            },
            tooltip: {
                y: {
                    formatter: (val) => val,
                },
            },
        },
    }),
    created() {
        this.chartOptions.yaxis.max = this.yMax;
        this.chartOptions.colors = this.chartColors;
        this.chartOptions.xaxis.categories = this.dateRange;
    },
};
</script>
