<template>
    <apexchart type="line" height="350" :options="chartOptions" :series="series" />
</template>

<script>
import VueApexCharts from 'vue-apexcharts';
export default {
    components: {
        apexchart: VueApexCharts,
    },
    props: ['series', 'yMax', 'chartColors'],
    data: () => ({
        chartOptions: {
            chart: {
                height: 350,
                type: 'line',
                dropShadow: {
                    enabled: true,
                    color: '#000',
                    top: 18,
                    left: 7,
                    blur: 10,
                    opacity: 0.2,
                },
                zoom: {
                    enabled: false,
                },
                toolbar: {
                    show: false,
                },
            },
            colors: ['#77B6EA', '#545454'],
            // dataLabels: {
            //     enabled: true,
            // },
            stroke: {
                curve: 'smooth',
                width: 2,
            },
            // title: {
            //     text: 'Average High & Low Temperature',
            //     align: 'left',
            // },
            grid: {
                borderColor: '#e7e7e7',
                row: {
                    colors: ['#f3f3f3', 'transparent'], // takes an array which will be repeated on columns
                    opacity: 0.5,
                },
            },
            markers: {
                size: 1,
            },
            xaxis: {
                categories: [
                    '0시',
                    '1시',
                    '2시',
                    '3시',
                    '4시',
                    '5시',
                    '6시',
                    '7시',
                    '8시',
                    '9시',
                    '10시',
                    '11시',
                    '12시',
                    '13시',
                    '14시',
                    '15시',
                    '16시',
                    '17시',
                    '18시',
                    '19시',
                    '20시',
                    '21시',
                    '22시',
                    '23시',
                ],
            },
            yaxis: {
                // title: {
                //     text: 'Temperature',
                // },
                min: 0,
            },
            legend: {
                position: 'top',
                horizontalAlign: 'right',
                floating: true,
            },
        },
    }),
    created() {
        this.chartOptions.yaxis.max = this.yMax;
        this.chartOptions.colors = this.chartColors;
    },
};
</script>
