<template>
    <v-container>
        <PagePath />
        <div class="content">
            <div class="search_option">
                <v-menu
                    ref="menu"
                    v-model="isPickerOpen"
                    class="data_picker"
                    :close-on-content-click="false"
                    :return-value.sync="dates"
                    transition="scale-transition"
                    offset-y
                >
                    <template v-slot:activator="{ on, attrs }">
                        <div>
                            <v-text-field
                                v-model="dateRangeText"
                                v-bind="attrs"
                                v-on="on"
                                outlined
                                prepend-inner-icon="mdi-calendar"
                                readonly
                                hide-details
                                class="white"
                            />
                        </div>
                    </template>
                    <v-date-picker v-model="dates" range no-title>
                        <v-spacer></v-spacer>
                        <v-btn text color="primary" @click="isPickerOpen = false"> 취소 </v-btn>
                        <v-btn text color="primary" @click="$refs.menu.save(dates)"> 확인 </v-btn>
                    </v-date-picker>
                </v-menu>
                <v-radio-group v-model="detectionOption" row class="detection_option">
                    <v-radio label="탐지 시각" color="#2a85ff" value="time"></v-radio>
                    <v-radio label="탐지 각도" color="#2a85ff" value="angle"></v-radio>
                </v-radio-group>
                <v-btn elevation="3" color="primary" class="btn_search" outlined>적용</v-btn>
                <button class="btn_xls"></button>
            </div>
            <div class="chart_area">
                <BarCharts v-if="chartsView" :series="barData" :yMax="160" :chartColors="chartColors" :dateRange="dateRange" />
            </div>
            <div class="notice">
                <span class="btn_notice">?</span>
                <p class="txt_notice">그래프를 클릭하면 탐지정보를 확인할 수 있습니다.</p>
            </div>
            <div class="chart_area">
                <LineCharts v-if="chartsView" :series="lineData" :yMax="30" :chartColors="chartColors" />
            </div>
        </div>
    </v-container>
</template>

<script>
import PagePath from '@/components/widget/PagePath';
import LineCharts from '@/components/widget/LineCharts';
import BarCharts from '@/components/widget/BarCharts';
import * as DateUtil from '@/common/DateUtil';
import * as FunctionUtil from '@/common/FunctionUtil';
export default {
    components: {
        PagePath,
        LineCharts,
        BarCharts,
    },
    data: () => ({
        // 달력 데이터
        dates: [DateUtil.getBeforeMonth(1), DateUtil.getCurrentDate()],
        isPickerOpen: false,
        detectionOption: 'time',
        // 차트 데이터
        chartsView: false,
        chartColors: ['#669900', '#AE0003', '#FF6600'],
        dateRange: ['1월', '2월', '3월', '4월', '5월', '6월', '7월', '8월', '9월', '10월', '11월', '12월'], // 검색 기간 설정 값
        lineData: [
            {
                name: '드론1',
                data: [],
            },
            {
                name: '드론2',
                data: [],
            },
            {
                name: '드론3',
                data: [],
            },
        ],
        barData: [
            {
                name: '드론1',
                data: [44, 55, 57, 56, 61, 58, 63, 60, 66, 70, 80, 50],
            },
            {
                name: '드론2',
                data: [76, 85, 101, 98, 87, 105, 91, 114, 94, 61, 58, 63],
            },
            {
                name: '드론3',
                data: [35, 41, 36, 26, 45, 48, 52, 53, 41, 98, 87, 105],
            },
        ],
    }),
    computed: {
        dateRangeText() {
            return this.dates.join(' ~ ');
        },
    },
    mounted() {
        this.lineData.forEach((item) => {
            for (let index = 0; index < 24; index++) {
                item.data.push(FunctionUtil.randomNum(0, 30));
            }
        });
        this.chartsView = true;
    },
    methods: {
        // randomNum(min, max) {
        //     var randNum = Math.floor(Math.random() * (max - min + 1)) + min;
        //     return randNum;
        // },
    },
};
</script>

<style lang="scss" scoped>
.search_option {
    @include hCenterAlign();
    overflow: hidden;
    width: 100%;
    height: 42px;
    .data_picker {
        width: 262px;
        margin-right: 5px;
    }
    .detection_option {
        width: 220px;
        margin: 22px 0 0 20px;
        padding: 0;
    }
    .btn_xls {
        width: 30px;
        height: 36px;
        margin-left: 30px;
        background: url('@/assets/history/btn_xls_on.svg') no-repeat 0 0;
        &:disabled {
            background-image: url('@/assets/history/btn_xls_off.svg');
        }
    }
}
.chart_area {
    border: 1px solid $color-main03;
    border-radius: 15px;
    padding: 10px;
    margin-top: 30px;
}
.notice {
    position: relative;
    height: 20px;
    margin-top: 10px;
    font-size: 500px;
    .btn_notice {
        position: absolute;
        top: 4px;
        right: 300px;
        display: inline-block;
        width: 20px;
        height: 20px;
        background: #c4ddf8;
        border-radius: 100%;
        font-size: 15px;
        text-align: center;
        color: #2882ff;
        cursor: pointer;
        &:hover {
            & + p {
                display: block;
            }
        }
    }
    .txt_notice {
        position: absolute;
        top: 0px;
        right: 26px;
        display: none;
        width: 269px;
        height: 28px;
        background: #deeeff;
        border-radius: 8px;
        font-size: 12px;
        line-height: 28px;
        text-align: center;
        color: #2a85ff;
    }
}
</style>
